def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_capacity in enumerate(bins):
        if bin_capacity <= 0:
            priorities[i] = float('inf')
            continue
        utilization = item / bin_capacity
        if utilization > 1:
            priorities[i] = float('inf')
            continue
        score = 0
        for j in range(1, 6):
            factor = j * utilization
            if factor < 0.3:
                score += np.sqrt(factor + 1)
            elif 0.3 <= factor < 0.7:
                score += np.sin(factor * np.pi)
            elif 0.7 <= factor < 1:
                score += np.cos(factor * np.pi / 2) + factor
            else:
                score += factor ** 3 / (j + 1)
            if j % 2 == 0:
                score *= (1 + 0.1 / (j + factor))
        if item < 0.5:
            if bin_capacity > item * 4:
                score *= 1.2
            else:
                score *= 0.9
        elif 0.5 <= item <= 1.5:
            if bin_capacity < item * 3:
                score *= 1.4
            elif bin_capacity > item * 6:
                score *= 0.7
            else:
                for k in range(1, 4):
                    score += np.tanh(k * utilization)
        else:
            for k in range(1, int(bin_capacity // item) + 1):
                increment = np.log(k + utilization + 1)
                if increment > 0.5:
                    score += increment * 0.5
                else:
                    score += increment ** 2
            if bin_capacity < item * 5:
                score *= 1.3
        if score < 0:
            score = abs(score) + 1
        priorities[i] = score
    return priorities
